    at java.lang.String.charAt(String.java:1555)
    at org.json.XMLTokener.unescapeEntity(XMLTokener.java:164)
    at org.json.XMLTokener.nextEntity(XMLTokener.java:148)
    at org.json.XML.toJSONObject(XML.java:784)
