    if (e.charAt(0) == '#') {
        if (e.length() < 2) {
            return "";  // or throw JSONException for invalid entity
        }
        if (e.charAt(1) == 'x' || e.charAt(1) == 'X') {
            cp = Integer.parseInt(e.substring(2), 16);
        } else {
            cp = Integer.parseInt(e.substring(1));
        }
        // ...
